#[test]
fn consolidation_lease_coordinates_processes_and_persists_attempt_interval() {
    let path = std::env::temp_dir().join(format!(
        "mindleak-consolidation-lease-{}-{}.db",
        std::process::id(),
        NOW
    ));
    let _ = std::fs::remove_file(&path);
    let first = GraphStore::new(db::open(path.to_str().unwrap()).unwrap());
    let second = GraphStore::new(db::open(path.to_str().unwrap()).unwrap());

    assert!(first
        .try_acquire_consolidation_lease("first", NOW, 300, 60)
        .unwrap());
    assert!(!second
        .try_acquire_consolidation_lease("second", NOW, 300, 60)
        .unwrap());
    assert!(first.release_consolidation_lease("first", NOW + 1).unwrap());
    assert!(!second
        .try_acquire_consolidation_lease("second", NOW + 30, 300, 60)
        .unwrap());
    assert!(second
        .try_acquire_consolidation_lease("second", NOW + 61, 300, 60)
        .unwrap());
    assert!(second
        .release_consolidation_lease("second", NOW + 62)
        .unwrap());
    assert!(first
        .try_acquire_consolidation_lease("manual", NOW + 62, 300, 0)
        .unwrap());

    drop(first);
    drop(second);
    std::fs::remove_file(path).unwrap();
}

#[test]
fn snapshot_only_includes_edges_between_returned_nodes() {
    let s = store();
    add_node(&s, "n1", NodeType::Artifact, "n1", NOW - 2);
    add_node(&s, "n2", NodeType::Artifact, "n2", NOW - 1);
    add_node(&s, "n3", NodeType::Artifact, "n3", NOW);
    s.upsert_edge(&raw_edge("n3", "n2", RelationType::Calls, 1.0, 168.0, NOW))
        .unwrap();
    s.upsert_edge(&raw_edge("n3", "n1", RelationType::Calls, 1.0, 168.0, NOW))
        .unwrap();

    let snap = s.snapshot(2, NOW).unwrap();
    let ids: Vec<_> = snap.nodes.iter().map(|n| n.node.id.clone()).collect();
    assert_eq!(ids.len(), 2);
    assert!(ids.contains(&"n3".to_string()) && ids.contains(&"n2".to_string()));
    // Edge to n1 excluded because n1 is outside the snapshot node set.
    assert_eq!(snap.edges.len(), 1);
    assert_eq!(snap.edges[0].target_id, "n2");
}

#[test]
fn export_graph_includes_all_nodes_and_only_active_edges() {
    let graph = store();
    add_node(&graph, "artifact:a", NodeType::Artifact, "a", NOW);
    add_node(&graph, "artifact:b", NodeType::Artifact, "b", NOW);
    add_node(&graph, "artifact:c", NodeType::Artifact, "c", NOW);
    graph
        .upsert_edge(&raw_edge(
            "artifact:a",
            "artifact:b",
            RelationType::Imports,
            1.0,
            168.0,
            NOW,
        ))
        .unwrap();
    graph
        .upsert_edge(&raw_edge(
            "artifact:b",
            "artifact:c",
            RelationType::RelatesTo,
            0.01,
            1.0,
            NOW - 10 * HOUR,
        ))
        .unwrap();

    let export = graph.export_graph(NOW).unwrap();

    assert_eq!(export.schema_version, 1);
    assert_eq!(export.nodes.len(), 3);
    assert_eq!(export.edges.len(), 1);
    assert_eq!(export.edges[0].relation, RelationType::Imports);
}

#[test]
fn backup_database_preserves_graph_state() {
    let graph = store();
    add_node(&graph, "artifact:a", NodeType::Artifact, "a", NOW);
    let path = std::env::temp_dir().join(format!(
        "mindleak-graph-backup-{}-{}.db",
        std::process::id(),
        NOW
    ));
    let _ = std::fs::remove_file(&path);

    graph.backup_database(&path).unwrap();

    let restored = GraphStore::new(db::open(path.to_str().unwrap()).unwrap());
    assert!(restored.get_node("artifact:a").unwrap().is_some());
    drop(restored);
    std::fs::remove_file(path).unwrap();
}

#[test]
fn reset_database_requires_exact_token_and_clears_memory_state() {
    let graph = store();
    add_node(&graph, "artifact:a", NodeType::Artifact, "a", NOW);
    crate::embed::upsert(&graph.conn, "artifact:a", "test", &[1.0], NOW).unwrap();
    crate::telemetry::record(
        &graph.conn,
        NOW,
        "tool_call",
        "graph_stats",
        "ok",
        Some(1),
        None,
    )
    .unwrap();
    assert!(graph
        .try_acquire_consolidation_lease("reset-test", NOW, 300, 60)
        .unwrap());

    assert!(graph.reset_database("yes").is_err());
    assert!(graph.get_node("artifact:a").unwrap().is_some());

    let outcome = graph.reset_database("RESET MINDLEAK").unwrap();
    assert_eq!(outcome.nodes_removed, 1);
    assert_eq!(outcome.embeddings_removed, 1);
    assert_eq!(outcome.telemetry_events_removed, 1);
    assert_eq!(outcome.maintenance_leases_removed, 1);
    assert_eq!(graph.counts(NOW).unwrap(), (0, 0));
}
